class Solution {
    public int numSub(String s) {
        int count = 0;
        int mod = 1000000007;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') {
                count += (count << 1) % mod;
            }
        }
        return count;
    }
}
